import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import "../styles/login.css";

const Login = () => {
  const [documento, setDocumento] = useState("");
  const [password, setPassword] = useState("");
  const [mostrarPassword, setMostrarPassword] = useState(false);
  const [mensajeError, setMensajeError] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!documento || !password) {
      setMensajeError("❌ Por favor, complete todos los campos antes de continuar.");
      return;
    }

    setMensajeError("");

    window.location.href = "/cuenta";
  };

  useEffect(() => {
    document.getElementById("year").textContent = new Date().getFullYear();
  }, []);

  return (
    <div className="bg-wrapper"> {/* 👈 SOLO ESTO SE AGREGÓ */}
      <div className="login-container">
        <h1 className="titulo">inicio</h1>
        <p className="subtitulo">bienvenido a nuestro menú de inicio.</p>

        <form className="formulario" onSubmit={handleSubmit}>
          
          <label>Documento</label>
          <div className="input-box">
            <span className="icon">👤</span>
            <input
              type="text"
              placeholder="XXX.XXX.XXX"
              value={documento}
              onChange={(e) => setDocumento(e.target.value)}
            />
          </div>

          <label>Password</label>
          <div className="input-box">
            <span className="icon">🔒</span>
            <input
              type={mostrarPassword ? "text" : "password"}
              placeholder="••••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />

            <span
              className="eye"
              onClick={() => setMostrarPassword(!mostrarPassword)}
              style={{ cursor: "pointer" }}
            >
              {mostrarPassword ? "🙈" : "👁️"}
            </span>
          </div>

          {mensajeError && (
            <p style={{ color: "#ff4c4c", fontWeight: "bold", marginTop: "10px" }}>
              {mensajeError}
            </p>
          )}

          <button type="submit" className="btn">
            Iniciar sesión
          </button>

          <div className="footer">
            <p>
              © <span id="year"></span> Financiero. Todos los derechos reservados.
            </p>
          </div>

          <p className="registro">
            ¿No tienes cuenta? <Link to="#">Regístrate aquí</Link>
          </p>

        </form>
      </div>
    </div>
  );
};

export default Login;
